/**
 * Catalogue de traductions pour l'interface APP (dashboard, profil,
 * groupes, etc.) — distinct de marketing-translations.ts (qui couvre la
 * vitrine publique).
 *
 * Pourquoi un nouveau catalogue ? La vitrine et l'app ont des besoins
 * très différents :
 *  - Vitrine : phrases marketing accrocheuses, ton commercial
 *  - App : labels courts, navigation, actions, messages d'état
 *
 * Le hook `useT()` retourne un sélecteur typé. Si une clé n'existe pas
 * dans la locale active, on retombe sur "fr" (langue de référence).
 *
 * Usage :
 *   const t = useT();
 *   <button>{t("common.save")}</button>
 *   <h1>{t("dashboard.greeting", { name: "Marie" })}</h1>
 */

import { useLocale } from "../locale-provider";

/**
 * Sprint AC-5 · Le catalog a grossi (113+ clés × 25 locales). Pour ne pas
 * exploser l'inférence TypeScript on annote APP_STRINGS comme un type
 * paramétré par locale plutôt que d'inférer le literal géant. AppStringKey
 * reste strict via `keyof typeof APP_STRINGS["fr"]` qui marche toujours
 * grâce au cast assertion `satisfies` dans le bloc FR.
 */
type LocaleCode =
  | "fr" | "en" | "es" | "pt" | "ar" | "sw" | "wo" | "ln" | "am"
  | "de" | "it" | "lb" | "ru" | "ja" | "ko" | "hi" | "zh" | "pcm"
  | "ha" | "yo" | "om" | "ig" | "ff" | "zu" | "ak"
  | "fr-cm" | "fr-ci"; // variantes camerounaise et ivoirienne

// Catalogue — chaque locale a un mapping clé → traduction.
// Le typage strict des clés (AppStringKey) repose sur le bloc FR.
