/**
 * Sprint AC-5 · `AppStringKey` reste strictement typé sur les clés du bloc
 * FR (single source of truth). On utilise une déclaration séparée pour ne
 * pas dépendre de l'inférence du literal entier de APP_STRINGS.
 */
export type AppStringKey = keyof typeof APP_STRINGS_FR_KEYS;
const APP_STRINGS_FR_KEYS = APP_STRINGS.fr as Record<string, string>;

/**
 * Hook qui retourne une fonction de traduction `t(key, vars?)`. Le hook
 * réagit aux changements de locale via `useLocale()` — donc tous les
 * composants qui utilisent `t()` se mettent à jour automatiquement quand
 * l'utilisateur change de langue dans son profil.
 */
export function useT(): (
  key: AppStringKey,
  vars?: Record<string, string>,
) => string {
  const { code } = useLocale();
  const dict =
    (APP_STRINGS as Record<string, Record<string, string>>)[code] ??
    APP_STRINGS.fr;
  return (key, vars) => {
    const tpl =
      dict[key] ?? (APP_STRINGS.fr as Record<string, string>)[key] ?? key;
    if (!vars) return tpl;
    return tpl.replace(/\{(\w+)\}/g, (_, k) => vars[k] ?? `{${k}}`);
  };
}
